{
var seed = GetInt(parameters, "seed", context.Seed);
var density = Math.Clamp(GetInt(parameters, "ringDensity", 6), 3, 16);
var ringThickness = GetFloat(parameters, "ringThickness", 0.3f);
var metallic = GetFloat(parameters, "metallic", 0.6f);
var shadowStrength = GetFloat(parameters, "shadowStrength", 0.4f);
var metalColor = GetColor(parameters, "metalColor", Color.FromRgb(180, 175, 170));
var darkColor = GetColor(parameters, "darkColor", Color.FromRgb(80, 75, 70));
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var mR = metalColor.R / 255f; var mG = metalColor.G / 255f; var mB = metalColor.B / 255f;
var dR = darkColor.R / 255f; var dG = darkColor.G / 255f; var dB = darkColor.B / 255f;

// Chainmail is a grid of interlocking rings
// Each cell has one horizontal ring and one vertical ring woven together
// The pattern repeats in a 2x2 tile arrangement for proper interlocking
var cellsPerRow = density;
var cellSize = 1f / cellsPerRow;
var ringRadius = cellSize * 0.45f;
var wireRadius = ringRadius * ringThickness;

// Offsets for the 2x2 interlocking pattern
var offsets = new (float dx, float dy)[] {
    (0.25f, 0.25f),   // horizontal ring
    (0.75f, 0.25f),   // vertical ring
    (0.25f, 0.75f),   // vertical ring
    (0.75f, 0.75f)    // horizontal ring
};
var ringTypes = new bool[] { true, false, false, true }; // true = horizontal, false = vertical

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    var bestDist = float.MaxValue;
    var bestHorizontal = true;
    var bestLayer = 0;

    // Evaluate which ring this pixel belongs to (nearest center)
    for (var i = 0; i < 4; i++)
    {
        var baseCellX = (int)MathF.Floor(u / cellSize);
        var baseCellY = (int)MathF.Floor(v / cellSize);

        // Check neighboring cells for overlapping rings
        for (var dx = -1; dx <= 1; dx++)
        {
            for (var dy = -1; dy <= 1; dy++)
            {
                var cellX = baseCellX + dx;
                var cellY = baseCellY + dy;

                // Wrap cell coordinates
                var wrappedCellX = ((cellX % cellsPerRow) + cellsPerRow) % cellsPerRow;
                var wrappedCellY = ((cellY % cellsPerRow) + cellsPerRow) % cellsPerRow;

                // Each cell has multiple ring centers based on the 2x2 pattern
                var cellOriginX = wrappedCellX * cellSize;
                var cellOriginY = wrappedCellY * cellSize;

                var subPattern = (wrappedCellX % 2) + (wrappedCellY % 2) * 2;
                var off = offsets[subPattern];
                var isHorizontal = ringTypes[subPattern];

                // Ring center in UV space
                var cx = cellOriginX + off.dx * cellSize;
                var cy = cellOriginY + off.dy * cellSize;

                var du = u - cx;
                var dv = v - cy;

                // Wrap distance for tileability
                du -= MathF.Round(du / 1f);
                dv -= MathF.Round(dv / 1f);

                var dist = MathF.Sqrt(du * du + dv * dv);

                // Distance from ring centerline (toroidal geometry)
                float centerlineDist;
                if (isHorizontal)
                {
                    var along = du;
                    var perp = MathF.Abs(dv);
                    // Ring is an ellipse: stretched horizontally
                    var alongNorm = along / (ringRadius * 1.2f);
                    var perpNorm = perp / ringRadius;
                    centerlineDist = MathF.Sqrt(alongNorm * alongNorm + perpNorm * perpNorm);
                }
                else
                {
                    var along = dv;
                    var perp = MathF.Abs(du);
                    var alongNorm = along / (ringRadius * 1.2f);
                    var perpNorm = perp / ringRadius;
                    centerlineDist = MathF.Sqrt(alongNorm * alongNorm + perpNorm * perpNorm);
                }

                // Check if within ring wire
                var surfaceDist = MathF.Abs(centerlineDist - 1f) * wireRadius;
                var innerDist = centerlineDist;

                if (surfaceDist < bestDist && centerlineDist > 0.5f && centerlineDist < 1.3f)
                {
                    bestDist = surfaceDist;
                    bestHorizontal = isHorizontal;
                    bestLayer = i;
                }
            }
        }
    }

    float r, g, b;

    if (bestDist < wireRadius * 0.5f)
    {
        // On a ring — compute shading
        var depthFactor = bestDist / (wireRadius * 0.5f);
        var baseR = Lerp(mR, dR, depthFactor * 0.3f);
        var baseG = Lerp(mG, dG, depthFactor * 0.3f);
        var baseB = Lerp(mB, dB, depthFactor * 0.3f);

        // Specular highlight
        var spec = (1f - depthFactor) * metallic * 0.5f;
        r = Math.Clamp(baseR + spec, 0f, 1f);
        g = Math.Clamp(baseG + spec * 0.95f, 0f, 1f);
        b = Math.Clamp(baseB + spec * 0.9f, 0f, 1f);

        // Layer-based shadow: lower layers are darker
        var layerShadow = (bestLayer % 2 == 1) ? (1f - shadowStrength * 0.15f) : 1f;
        r *= layerShadow;
        g *= layerShadow;
        b *= layerShadow;
    }
    else
    {
        // Background / between rings — shadow
        var bgShadow = 1f - shadowStrength * 0.4f;
        r = dR * bgShadow;
        g = dG * bgShadow;
        b = dB * bgShadow;

        // Ambient glow from nearby rings
        var ambient = (1f - MathF.Min(bestDist / (wireRadius * 2f), 1f)) * 0.1f;
        r = Math.Clamp(r + ambient, 0f, 1f);
        g = Math.Clamp(g + ambient, 0f, 1f);
        b = Math.Clamp(b + ambient, 0f, 1f);
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
